const d = $input.first().json;
const s = d.data || d;
const risk = s.risk || {};
const funnel = s.funnel || {};
const incidents = s.incidents || {};
const riskAction = risk.action || 'NORMAL';
const riskScore = risk.score || 0;
const pendingPct = ((risk.pendingRatio || 0) * 100).toFixed(1);
const totalLeads = funnel.totalLeads || 0;
const invited = funnel.invited || 0;
const accepted = funnel.accepted || 0;
const replied = funnel.replied || 0;
const openIncidents = incidents.openCount || 0;
const criticalIncidents = incidents.criticalCount || 0;
const quarantined = s.system?.quarantined || false;
const date = s.localDate || new Date().toISOString().slice(0,10);
const hour = new Date().getHours();
const session = hour < 12 ? 'mattina' : 'pomeriggio';
const prompt = 'Sei l\'orchestratore LinkedIn Bot anti-ban. Analizza e decidi.\n\nDATI (sessione ' + session + ' - ' + date + '):\n- Risk: ' + riskAction + ' | Score: ' + riskScore + '/100 | Pending: ' + pendingPct + '%\n- Funnel: ' + totalLeads + ' leads | ' + invited + ' invitati | ' + accepted + ' accettati | ' + replied + ' replies\n- Incidenti: ' + openIncidents + ' (' + criticalIncidents + ' critici) | Quarantena: ' + quarantined + '\n\nREGOLE (priorita decrescente):\n1. quarantined=true o criticalIncidents>0 → SKIP\n2. pendingPct>65 o riskAction=STOP → SKIP\n3. riskAction=WARN|LOW_ACTIVITY → REDUCE workflow=check\n4. riskAction=NORMAL score<30 → PROCEED workflow=all\n5. riskAction=NORMAL score 30-60 → PROCEED workflow=check\n6. pomeriggio + accepted>0 → preferire workflow=message\n\nRispondi SOLO JSON valido senza markdown: {"decision":"PROCEED|REDUCE|SKIP","workflow":"all|check|message|warmup","reason":"max 12 parole"}';
const claudeBody = JSON.stringify({ model: 'claude-sonnet-4-6', max_tokens: 100, messages: [{ role: 'user', content: prompt }] });
const out = { riskAction, riskScore, pendingPct: parseFloat(pendingPct), totalLeads, invited, accepted, replied, openIncidents, criticalIncidents, quarantined, date, session, claudeBody };
return [{ json: out }];

const response = $input.first().json;
const metrics = $('Parse Metrics').first().json;
let decision = 'PROCEED';
let workflow = 'all';
let reason = 'rule-based fallback';
try {
  const content = response.content?.[0]?.text || '';
  const match = content.match(/\{[\s\S]*?\}/);
  if (match) {
    const p = JSON.parse(match[0]);
    if (['PROCEED','REDUCE','SKIP'].includes(p.decision)) {
      decision = p.decision;
      workflow = ['all','check','message','warmup','invite'].includes(p.workflow) ? p.workflow : 'check';
      reason = (p.reason || '').slice(0, 60);
    }
  }
} catch(e) {}
if (reason === 'rule-based fallback') {
  const r = metrics.riskAction;
  if (r === 'STOP' || metrics.criticalIncidents > 0 || metrics.quarantined) { decision = 'SKIP'; workflow = 'check'; reason = 'risk ' + r + ' → skip'; }
  else if (r === 'WARN' || r === 'LOW_ACTIVITY') { decision = 'REDUCE'; workflow = 'check'; reason = 'risk ' + r + ' → check'; }
  else { decision = 'PROCEED'; workflow = metrics.riskScore < 30 ? 'all' : 'check'; reason = 'risk NORMAL'; }
}
const emojis = { PROCEED: '✅', REDUCE: '🟡', SKIP: '🛑' };
const e = emojis[decision] || '❓';
const sessEmoji = metrics.session === 'mattina' ? '☀️' : '🌆';
const notifyMsg = sessEmoji + ' *LinkedIn Bot ' + metrics.session + '* — ' + metrics.date + '\n' + e + ' Decisione: *' + decision + '* (' + workflow + ')\n' + '🤖 _"' + reason + '"_\n\nHai 10 min per bloccare — invia /pause al bot.';
const reportMsg = sessEmoji + ' *LinkedIn Bot ' + metrics.session + '* — ' + metrics.date + '\n' + e + ' Decisione: *' + decision + '* (' + workflow + ')\n' + '🤖 _"' + reason + '"_\n\n📊 Risk: ' + metrics.riskAction + ' (score ' + metrics.riskScore + ') | Pending: ' + metrics.pendingPct + '%\n👥 ' + metrics.totalLeads + ' leads | ' + metrics.invited + ' invitati | ' + metrics.accepted + ' accettati | ' + metrics.replied + ' replies\n\n_[Orchestrator v2]_';
const out = { decision, workflow, reason, notifyMsg, reportMsg, session: metrics.session };
return [{ json: out }];

const snap = $input.first().json;
const data = snap.data || snap;
const isVetoed = !!(data.system?.pausedUntil || data.system?.quarantined);
const out = { isVetoed: isVetoed ? 'yes' : 'no' };
return [{ json: out }];
